const runId = $input.first().json.runId;
const source = $input.first().json.source || {};
const plainText = source.plainText || '';
const sections = source.sections || [];
const metadata = source.metadata || {};

console.log(`[WF03][${runId}] Running quality checks...`);

const warnings = [];
const errors = [];
let score = 1.0;

// 1. Minimum word count (at least 300 words for a real BRD)
const wordCount = metadata.wordCount || plainText.split(/\s+/).filter(Boolean).length;
if (wordCount < 300) {
  errors.push(`Document too short: ${wordCount} words (minimum 300 required)`);
  score -= 0.5;
} else if (wordCount < 800) {
  warnings.push(`Low word count: ${wordCount} words. Consider a more detailed source document.`);
  score -= 0.1;
}

// 2. Section density
if (sections.length === 0) {
  warnings.push('No structured sections detected. Analysis will rely on full text only.');
  score -= 0.1;
} else if (sections.length < 3) {
  warnings.push(`Only ${sections.length} section(s) detected. Document may lack structure.`);
  score -= 0.05;
}

// 3. Heading presence check
const hasHeadings = sections.some(s => s.level === 1) || /^#+\s/m.test(plainText);
if (!hasHeadings) {
  warnings.push('No top-level headings detected. Structure will be inferred from content.');
  score -= 0.05;
}

// 4. OCR noise detection (high ratio of special chars = noisy OCR)
const specialCharRatio = (plainText.match(/[^a-zA-Z0-9\s.,;:!?'"()\-]/g) || []).length / Math.max(plainText.length, 1);
if (specialCharRatio > 0.08) {
  warnings.push(`High OCR noise detected (${(specialCharRatio * 100).toFixed(1)}% non-standard characters). Quality may be affected.`);
  score -= 0.1;
}

// 5. Empty/corrupted check
if (plainText.trim().length < 50) {
  errors.push('Document appears empty or corrupted. No readable content found.');
  score = 0;
}

// 6. Sample availability
const hasSamples = $input.first().json.samples && $input.first().json.samples.length > 0;
if (!hasSamples) {
  warnings.push('No sample documents provided. Output will not be blueprint-aligned.');
  score -= 0.05;
}

// Determine status
const finalScore = Math.max(0, Math.min(1, score));
let status;
if (errors.length > 0) {
  status = 'fail';
} else if (warnings.length > 0) {
  status = 'pass_with_warning';
} else {
  status = 'pass';
}

console.log(`[WF03][${runId}] Quality result: ${status} (score: ${finalScore.toFixed(2)})`);

return [{
  json: {
    runId,
    source: $input.first().json.source,
    samples: $input.first().json.samples,
    options: $input.first().json.options,
    quality: {
      status,
      score: parseFloat(finalScore.toFixed(2)),
      warnings,
      errors
    }
  }
}];
